  `category` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Categoría (Cemento, Arena, Hierro, etc.)',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Activo' COMMENT 'Estado: Activo, Inactivo',
  `created_date` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Fecha de creación',
  `updated_date` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT 'Fecha de última actualización',
  PRIMARY KEY (`id_Materials`),
  UNIQUE KEY `name` (`name`),
  KEY `idx_materials_name` (`name`),
  KEY `idx_materials_status` (`status`),
  KEY `idx_materials_category` (`category`),
  KEY `idx_materials_stock_low` (`current_stock`,`minimum_stock`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Tabla de materiales de construcción con stock';
